export interface RenderConfig {
    width: number;
    height: number;
    backgroundColor?: string;
    antialias?: boolean;
}

export class Renderer {
    private engine: unknown;
    private canvas: HTMLCanvasElement | null = null;
    private ctx: CanvasRenderingContext2D | null = null;
    private config: RenderConfig;
    private initialized: boolean = false;

    constructor(engine: unknown, config?: Partial<RenderConfig>) {
        this.engine = engine;
        this.config = {
            width: 800,
            height: 600,
            backgroundColor: '#1a1a2e',
            antialias: true,
            ...config
        };
    }

    async initialize(): Promise<void> {
        console.log('🎨 Renderer 初始化...');
        this.initialized = true;
        console.log('✅ Renderer 初始化完成');
    }

    attach(canvas: HTMLCanvasElement): void {
        this.canvas = canvas;
        this.ctx = canvas.getContext('2d', {
            alpha: false,
            desynchronized: true
        });

        if (this.ctx) {
            this.ctx.imageSmoothingEnabled = this.config.antialias ?? true;
        }

        this.resize(this.config.width, this.config.height);
    }

    resize(width: number, height: number): void {
        if (this.canvas) {
            this.canvas.width = width;
            this.canvas.height = height;
            this.config.width = width;
            this.config.height = height;
        }
    }

    clear(): void {
        if (this.ctx) {
            this.ctx.fillStyle = this.config.backgroundColor ?? '#1a1a2e';
            this.ctx.fillRect(0, 0, this.config.width, this.config.height);
        }
    }

    getContext(): CanvasRenderingContext2D | null {
        return this.ctx;
    }

    getCanvas(): HTMLCanvasElement | null {
        return this.canvas;
    }

    getWidth(): number {
        return this.config.width;
    }

    getHeight(): number {
        return this.config.height;
    }

    drawImage(
        image: CanvasImageSource,
        x: number,
        y: number,
        width?: number,
        height?: number
    ): void {
        if (!this.ctx) return;

        if (width !== undefined && height !== undefined) {
            this.ctx.drawImage(image, x, y, width, height);
        } else {
            this.ctx.drawImage(image, x, y);
        }
    }

    drawRect(
        x: number,
        y: number,
        width: number,
        height: number,
        color: string,
        fill: boolean = true
    ): void {
        if (!this.ctx) return;

        if (fill) {
            this.ctx.fillStyle = color;
            this.ctx.fillRect(x, y, width, height);
        } else {
            this.ctx.strokeStyle = color;
            this.ctx.strokeRect(x, y, width, height);
        }
    }

    drawCircle(
        x: number,
        y: number,
        radius: number,
        color: string,
        fill: boolean = true
    ): void {
        if (!this.ctx) return;

        this.ctx.beginPath();
        this.ctx.arc(x, y, radius, 0, Math.PI * 2);

        if (fill) {
            this.ctx.fillStyle = color;
            this.ctx.fill();
        } else {
            this.ctx.strokeStyle = color;
            this.ctx.stroke();
        }
    }

    drawText(
        text: string,
        x: number,
        y: number,
        color: string = '#ffffff',
        font: string = '16px Arial'
    ): void {
        if (!this.ctx) return;

        this.ctx.font = font;
        this.ctx.fillStyle = color;
        this.ctx.fillText(text, x, y);
    }

    setAlpha(alpha: number): void {
        if (this.ctx) {
            this.ctx.globalAlpha = Math.max(0, Math.min(1, alpha));
        }
    }

    destroy(): void {
        this.ctx = null;
        this.canvas = null;
        this.initialized = false;
    }
}

export default Renderer;
